// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Compute weather icon/emoji based on condition
  // Compute weather icon name based on condition
  const getWeatherIcon = useCallback((condition: string) => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return 'sun';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('cloud')) return 'cloud';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return 'cloud-rain';
    if (lowerCondition.includes('overcast')) return 'cloud';
    if (lowerCondition.includes('partly')) return 'cloud-sun';
    if (lowerCondition.includes('snow')) return 'snowflake';
    if (lowerCondition.includes('storm') || lowerCondition.includes('thunder') || lowerCondition.includes('thunderstorm')) return 'cloud-lightning';
    if (lowerCondition.includes('drizzle')) return 'cloud-drizzle';
    if (lowerCondition.includes('hail') || lowerCondition.includes('sleet')) return 'cloud-hail';
    if (lowerCondition.includes('wind')) return 'wind';
    if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return 'cloud-fog';
    return 'cloud-sun';
  }, []);

  // Get condition-based accent color
  const getConditionColor = useCallback((condition: string) => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain') || lowerCondition.includes('storm')) {
      return 'var(--ggui-color-info-500, #06b6d4)';
    }
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) {
      return 'var(--ggui-color-warning-500, #f59e0b)';
    }
    return 'var(--ggui-color-primary-500, #0ea5e9)';
  }, []);

  return {
    getWeatherIcon,
    getConditionColor,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Main Weather Card */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={16}>
            {/* City and Condition Header */}
            <Stack direction="horizontal" align="center" justify="between">
              <Stack gap={8} align="start">
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{props.city}</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
              </Stack>
              <Icon name={state.getWeatherIcon(props.condition)} size={64} color={state.getConditionColor(props.condition)} />
            </Stack>

            {/* Temperature Display */}
            <Box padding={24} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={12}>
              <Stack gap={8} align="center">
                <Text variant="bodySmall" color="var(--ggui-color-primary-600, #0284c7)">Current Temperature</Text>
                <Heading level={1} color="var(--ggui-color-primary-900, #0c4a6e)">
                  {props.temperature}°{props.unit}
                </Heading>
              </Stack>
            </Box>

            {/* Humidity and Wind Speed */}
            <Stack direction="horizontal" gap={16}>
              <Card shadow="sm" padding={16} radius="md" style={{ flex: 1 }}>
                <Stack gap={8} align="center">
                  <Icon name="droplets" size={24} color="var(--ggui-color-info-500, #06b6d4)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Heading>
                </Stack>
              </Card>

              <Card shadow="sm" padding={16} radius="md" style={{ flex: 1 }}>
                <Stack gap={8} align="center">
                  <Icon name="wind" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} {props.unit === 'C' ? 'm/s' : 'mph'}</Heading>
                </Stack>
              </Card>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding={20} radius="lg">
            <Stack gap={12}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-Day Forecast</Text>
              <Row gap={12} wrap justify="start">
                {props.forecast?.map((day, index) => (
                  <Box
                    key={index}
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius={8}
                    style={{ flex: 1, minWidth: '80px' }}
                  >
                    <Stack gap={8} align="center">
                      {/* Day name */}
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                        {day.day || `Day ${index + 1}`}
                      </Text>
                      {/* Weather icon */}
                      <Icon name={day.icon || state.getWeatherIcon(day.day ? 'partly cloudy' : 'sunny')} size={32} />
                      {/* High/Low temps */}
                      <Stack gap={4} align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" align="center">
                          <span style={{ fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>{day.high ?? '—'}°{props.unit}</span>
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                          {day.low ?? '—'}°{props.unit}
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const validateName = useCallback((value: string): string => {
    if (!value.trim()) return 'Name is required';
    return '';
  }, []);

  const validateEmail = useCallback((value: string): string => {
    if (!value.trim()) return 'Email is required';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(value)) return 'Invalid email format';
    return '';
  }, []);

  // Handlers for name and email with inline validation
  const handleNameChange = useCallback((value: string) => {
    setName(value);
    setNameError(validateName(value));
  }, [validateName]);

  const handleEmailChange = useCallback((value: string) => {
    setEmail(value);
    setEmailError(validateEmail(value));
  }, [validateEmail]);

  // Computed values
  const isStep1Valid = name.trim() && !nameError && email.trim() && !emailError;
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true; // Features are optional
  const isStep4Valid = comments.length <= 500; // Comments optional but enforce char limit

  // Feature toggle handler
  const handleFeatureToggle = useCallback((feature: string) => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  // Submit handler
  // Submit handler
  const handleSubmit = useCallback(() => {
    if (comments.length > 500) {
      return; // Prevent submission if over 500 chars
    }
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features: selectedFeatures,
      comments,
    });
  }, [submit, name, email, satisfaction, selectedFeatures, comments]);

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  return {
    submit,
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    nameError,
    emailError,
    satisfaction,
    setSatisfaction,
    selectedFeatures,
    handleFeatureToggle,
    comments,
    setComments,
    isStep1Valid,
    isStep2Valid,
    isStep3Valid,
    isStep4Valid,
    handleNext,
    handleBack,
    handleNameChange,
    handleEmailChange,
    handleSubmit,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Create satisfaction options from props labels
  // Create satisfaction options from props labels
  const satisfactionLabels = props.satisfactionLabels || [];
  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: label,
  }));

  const featureOptions = props.featureOptions || [];
  const featureCheckboxes = featureOptions.map((feature) => ({
    label: feature,
    checked: state.selectedFeatures.includes(feature),
  }));

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Progress Bar */}
        <Box>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {state.currentStep} of 4
            </Text>
            <Progress value={state.currentStep} max={4} variant="default" />
          </Stack>
        </Box>

        {/* Step 1: Name and Email */}
        {state.currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={state.name}
                onChange={state.handleNameChange}
                error={state.nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email address"
                value={state.email}
                onChange={state.handleEmailChange}
                error={state.emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Level"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {state.currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap={12}>
                {(props.featureOptions || []).map((feature, index) => (
                  <Checkbox
                    key={index}
                    label={feature}
                    checked={state.selectedFeatures.includes(feature)}
                    onChange={() => state.handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {state.currentStep === 4 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback (optional)"
                value={state.comments}
                onChange={state.setComments}
                maxLength={500}
                showCount
                rows={6}
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {state.currentStep === 5 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Box paddingY={8} paddingX={0}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Name
                    </Text>
                    <Text variant="body">{state.name}</Text>
                  </Stack>
                </Box>
                <Divider />
                <Box paddingY={8} paddingX={0}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Email
                    </Text>
                    <Text variant="body">{state.email}</Text>
                  </Stack>
                </Box>
                <Divider />
                <Box paddingY={8} paddingX={0}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Satisfaction
                    </Text>
                    <Text variant="body">
                      {satisfactionLabels.length > 0 && parseInt(state.satisfaction, 10) >= 1 && parseInt(state.satisfaction, 10) <= satisfactionLabels.length ? satisfactionLabels[parseInt(state.satisfaction, 10) - 1] : 'Not selected'}
                    </Text>
                  </Stack>
                </Box>
                <Divider />
                <Box paddingY={8} paddingX={0}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Features of Interest
                    </Text>
                    <Stack direction="horizontal" gap={8} wrap>
                      {state.selectedFeatures.length > 0 ? (
                        state.selectedFeatures.map((feature, index) => (
                          <Badge key={index} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))
                      ) : (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          None selected
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Box>
                <Divider />
                <Box paddingY={8} paddingX={0}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Comments
                    </Text>
                    <Text variant="body">
                      {state.comments || 'No comments provided'}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap={8}>
            {state.currentStep < 5 && (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={
                  (state.currentStep === 1 && !state.isStep1Valid) ||
                  (state.currentStep === 2 && !state.isStep2Valid) ||
                  (state.currentStep === 3 && !state.isStep3Valid) ||
                  (state.currentStep === 4 && !state.isStep4Valid)
                }
              >
                {state.currentStep === 4 ? 'Review' : 'Next'}
              </Button>
            )}
            {state.currentStep === 4 && (
              <Button variant="primary" onClick={() => state.setCurrentStep(5)}>
                Review
              </Button>
            )}
            {state.currentStep === 5 && (
              <Button variant="primary" onClick={state.handleSubmit}>
                Submit
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State management
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingTaskInColumn, setAddingTaskInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Listen for real-time stream events via window listener
  React.useEffect(() => {
    const handler = (e: any) => {
      const event = e.detail as StreamTaskChanged;
      if (event.action === 'create' && event.task) {
        setLocalTasks((prev) => [...prev, event.task!]);
      } else if (event.action === 'move' && event.task) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === event.task!.id ? event.task! : t))
        );
      } else if (event.action === 'edit' && event.task) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === event.task!.id ? event.task! : t))
        );
      } else if (event.action === 'delete' && event.task?.id) {
        setLocalTasks((prev) => prev.filter((t) => t.id !== event.task!.id));
      }
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  // Also update from useStream hook when available
  React.useEffect(() => {
    if (taskChanged.latest) {
      const event = taskChanged.latest;
      if (event.action === 'create' && event.task) {
        setLocalTasks((prev) => [...prev, event.task!]);
      } else if (event.action === 'move' && event.task) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === event.task!.id ? event.task! : t))
        );
      } else if (event.action === 'edit' && event.task) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === event.task!.id ? event.task! : t))
        );
      } else if (event.action === 'delete' && event.task?.id) {
        setLocalTasks((prev) => prev.filter((t) => t.id !== event.task!.id));
      }
    }
  }, [taskChanged.latest]);

  // Handle task move via dropdown
  const handleMoveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    },
    [taskUpdate]
  );

  // Handle add task submission
  // Handle add task submission - ALWAYS to 'To Do' column
  const handleAddTask = useCallback(
    () => {
      if (newTaskTitle.trim()) {
        const taskId = `task-${Date.now()}`;
        const newTask = {
          id: taskId,
          title: newTaskTitle,
          priority: newTaskPriority,
          column: 'todo',
          assignee: '',
          dueDate: '',
        };
        setLocalTasks((prev) => [...prev, newTask]);
        taskUpdate({
          action: 'create',
          taskId,
          data: { column: 'todo', priority: newTaskPriority, title: newTaskTitle },
        });
        setNewTaskTitle('');
        setNewTaskPriority('medium');
        setAddingTaskInColumn(null);
      }
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  // Compute task counts per column
  // Compute task counts per column
  const taskCountByColumn = (props.columns || []).reduce(
    (acc, col) => {
      const count = (state.localTasks || []).filter((t) => (t.column ?? 'todo') === col.id).length;
      acc[col.id || ''] = count;
      return acc;
    },
    {} as Record<string, number>
  );

  const completedCount = localTasks.filter((t) => t.column === 'done').length;
  const totalCount = localTasks.length;

  return {
    taskUpdate,
    taskChanged,
    localTasks,
    addingTaskInColumn,
    setAddingTaskInColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    handleMoveTask,
    handleAddTask,
    editingTaskId,
    setEditingTaskId,
    editingTaskTitle,
    setEditingTaskTitle,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={16} borderRadius={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap={32} align="center">
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Total Tasks:
                </Text>
                <Text variant="label" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                  {state.totalCount}
                </Text>
              </Stack>
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Completed:
                </Text>
