}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const lowerQuery = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      el.name?.toLowerCase().includes(lowerQuery) ||
      el.symbol?.toLowerCase().includes(lowerQuery)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Category to color mapping
  const categoryColors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
    'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition metal': 'var(--ggui-color-info-100, #cffafe)',
    'lanthanide': 'var(--ggui-color-primary-100, #e0f2fe)',
    'actinide': 'var(--ggui-color-success-100, #dcfce7)',
    'nonmetal': 'var(--ggui-color-success-50, #f0fdf4)',
    'halogen': 'var(--ggui-color-warning-50, #fffbeb)',
    'noble gas': 'var(--ggui-color-error-50, #fef2f2)',
    'semimetal': 'var(--ggui-color-secondary-100, #f3f4f6)',
  };

  const getCategoryColor = useCallback((category?: string) => {
    if (!category) return 'var(--ggui-color-surface, #fafafa)';
    return categoryColors[category.toLowerCase()] || 'var(--ggui-color-surface, #fafafa)';
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    filteredElements,
    selectedElement,
    setSelectedElement,
    categories,
    getCategoryColor,
  };
}

