  const specifications = Array.isArray(product.specifications) ? (product.specifications as Array<{ key?: string; value?: string }>) : [];
  const reviews = Array.isArray(product.reviews) ? (product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>) : [];

