              {product.name || 'Product Image'}
            </Text>
          </Box>

          {/* Product Details */}
          <Stack gap={16} align="start" style={{ flex: 1 }}>
            <Heading level={1}>{product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Text variant="body" size="xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
              {product.currency || '$'}{product.price?.toFixed(2) || '0.00'}
            </Text>

            {/* Rating */}
            <Stack direction="horizontal" gap={8} align="center">
              <Stack direction="horizontal" gap={2}>
                {ratingStars.map((filled, i) => (
                  <Icon key={i} name={filled ? 'star' : 'star'} size={20} color={filled ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'} />
                ))}
              </Stack>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {product.rating?.toFixed(1) || '0'} ({product.reviewCount || 0} reviews)
              </Text>
            </Stack>

            {/* Stock Badge */}
            <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
              {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
            </Badge>
          </Stack>
        </Stack>

        {/* Middle Section: Tabs */}
        <Tabs
          variant="line"
          items={[
            {
              key: 'description',
              label: 'Description',
              content: <Text variant="body">{product.description || 'No description available'}</Text>,
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Table
                  columns={[
                    { key: 'key', header: 'Property' },
                    { key: 'value', header: 'Value' },
                  ]}
                  data={specifications}
                />
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Stack gap={16}>
                  {reviews.length === 0 ? (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet</Text>
                  ) : (
                    reviews.map((review, idx) => (
                      <Card key={idx} padding={16} shadow="sm">
                        <Stack gap={8}>
                          <Stack direction="horizontal" gap={8} align="center" justify="between">
                            <Text variant="label" weight="semibold">{review.author || 'Anonymous'}</Text>
                            <Stack direction="horizontal" gap={2}>
                              {Array.from({ length: 5 }, (_, i) => i < (review.rating || 0)).map((filled, i) => (
                                <Icon key={i} name="star" size={16} color={filled ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'} />
                              ))}
                            </Stack>
                          </Stack>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review.date || ''}</Text>
                          <Text variant="body">{review.text || ''}</Text>
                        </Stack>
                      </Card>
                    ))
                  )}
                </Stack>
              ),
            },
          ]}
          activeKey={activeTab}
          onChange={setActiveTab}
        />

        {/* Bottom Section: Quantity & Add to Cart */}
        <Card padding={20} shadow="md">
          <Stack direction="horizontal" gap={16} align="center" justify="between">
            <Stack direction="horizontal" gap={12} align="center">
              <Text variant="label">Quantity:</Text>
              <Stack direction="horizontal" gap={8} align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setQuantity(quantity - 1)}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Text style={{ minWidth: '40px', textAlign: 'center' }} variant="body" weight="semibold">{quantity}</Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setQuantity(quantity + 1)}
                  disabled={quantity >= stock}
                >
                  +
                </Button>
              </Stack>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">(Max: {stock})</Text>
            </Stack>
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

