              const messageKey = msg.timestamp ? `${msg.sender}-${msg.timestamp}` : `msg-${idx}`;

              return (
                <Box
                  key={messageKey}
                  style={{
                    display: 'flex',
                    flexDirection: isCurrentUser ? 'row-reverse' : 'row',
                    alignItems: 'flex-end',
                    gap: 'var(--ggui-spacing-2, 8px)',
                    marginBottom: sameAsPrevious ? 0 : 'var(--ggui-spacing-2, 8px)'
                  }}
                >
                  {/* Avatar (only first message from sender) */}
                  <Avatar
                    name={msg.sender || 'Unknown'}
                    size={32}
                    shape='circle'
                    style={{ visibility: sameAsPrevious ? 'hidden' : 'visible', flexShrink: 0 }}
                  />

                  {/* Message Bubble */}
                  <Box
                    style={{
                      maxWidth: '60%',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      background: isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      wordWrap: 'break-word'
                    }}
                  >
                    {/* Sender name (only for other users, only on first message) */}
                    {!isCurrentUser && !sameAsPrevious && (
                      <Text
                        variant='label'
                        color='var(--ggui-color-onSurfaceVariant, #52525b)'
                        style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        {msg.sender}
                      </Text>
                    )}

                    {/* Message Text */}
                    <Text
                      variant='body'
                      color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {msg.text}
                    </Text>

                    {/* Timestamp */}
                    <Text
                      variant='caption'
                      color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                      style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Box>
                </Box>
              );
            })
          )}
          <div ref={state.messagesEndRef} />
        </Box>

        {/* Input Area */}
        <Box paddingX='var(--ggui-spacing-4, 16px)' paddingY='var(--ggui-spacing-4, 16px)' borderRadius='0' style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', display: 'flex', gap: 'var(--ggui-spacing-2, 8px)', alignItems: 'flex-end' }}>
          <TextArea
            label=''
            placeholder='Type a message...'
