            onChange={state.setInputText}
            rows={1}
            style={{
              flex: 1,
              resize: 'none',
              maxHeight: '120px'
            }}
            onKeyDown={state.handleKeyDown}
          />
          <Button
            variant='primary'
            size='md'
            disabled={!state.inputText.trim()}
            onClick={state.handleSendMessage}
            rightIcon={<Icon name='send' size={18} />}
          >
            Send
          </Button>
        </Box>
      </Card>
    </Container>
  );
}

