import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { useMotion } from '@ggui-ai/design/primitives';
import { useStream } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Local state for stocks and flash highlight animations
  const [stocks, setStocks] = useState(props.stocks || []);
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());

  // Subscribe to ggui:agent-data events for real-time stream updates
  React.useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data?.priceUpdate) {
        const update = data.priceUpdate;
        setStocks((prevStocks) => {
          return prevStocks.map((stock) => {
            if (stock.symbol === update.symbol) {
              // Trigger flash animation for this symbol
              setFlashingSymbols((prev) => new Set(prev).add(update.symbol || ''));
              // Clear flash after 600ms
              setTimeout(() => {
                setFlashingSymbols((prev) => {
                  const next = new Set(prev);
                  next.delete(update.symbol || '');
                  return next;
                });
              }, 600);
              // Return updated stock
              return {
                ...stock,
                price: update.price !== undefined ? update.price : stock.price,
                change: update.change !== undefined ? update.change : stock.change,
                changePercent: update.changePercent !== undefined ? update.changePercent : stock.changePercent,
              };
            }
            return stock;
          });
        });
        setLastUpdated(new Date());
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // When new price updates arrive via stream, merge them into stocks array and trigger flash animation
  React.useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        return prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            // Trigger flash animation for this symbol
            setFlashingSymbols((prev) => new Set(prev).add(update.symbol || ''));
            // Clear flash after 600ms
            setTimeout(() => {
              setFlashingSymbols((prev) => {
                const next = new Set(prev);
                next.delete(update.symbol || '');
                return next;
              });
            }, 600);
            // Return updated stock
            return {
              ...stock,
              price: update.price !== undefined ? update.price : stock.price,
              change: update.change !== undefined ? update.change : stock.change,
              changePercent: update.changePercent !== undefined ? update.changePercent : stock.changePercent,
            };
          }
          return stock;
        });
      });
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  return {
    stocks,
    flashingSymbols,
    lastUpdated,
    priceUpdate,
    marketStatus,
  };
}


export default function Component(props: Props) {
  const state = useComponent(props);
  const { stocks, flashingSymbols, lastUpdated, marketStatus } = state;
  const { motionEnabled } = useMotion();

  // Determine market status text
  const marketStatusText = marketStatus.latest?.status === 'open' ? 'Market Open' : 'Market Closed';
  const marketStatusColor =
    marketStatus.latest?.status === 'open'
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-outline, #d4d4d8)';

  // Inject motion keyframes and CSS for responsive grid and flash animation
  const styleId = 'stock-ticker-styles';
  React.useEffect(() => {
    if (!document.getElementById(styleId)) {
      const style = document.createElement('style');
      style.id = styleId;
      style.textContent = `
        @keyframes ggui-flash-highlight {
          0% {
            border-color: currentColor;
            background-color: currentColor;
          }
          50% {
            border-color: currentColor;
            background-color: currentColor;
          }
          100% {
            border-color: inherit;
            background-color: inherit;
          }
        }
        .stock-ticker-grid {
          display: grid;
          grid-template-columns: 1fr;
          gap: var(--ggui-spacing-4, 16px);
        }
        @media (min-width: 768px) {
          .stock-ticker-grid {
            grid-template-columns: repeat(3, 1fr);
          }
        }
        .stock-card-flash {
          animation: ggui-flash-highlight 600ms ease-in-out forwards;
        }
      `;
      document.head.appendChild(style);
    }
  }, []);

  return (
    <Container maxWidth="3xl" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header with title and last updated timestamp */}
        <Box>
          <Stack direction="horizontal" justify="between" align="center" gap={16}>
            <Stack gap={8}>
              <Heading level={1}>Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {lastUpdated.toLocaleTimeString()}
              </Text>
            </Stack>
            <Badge variant={marketStatus.latest?.status === 'open' ? 'success' : 'default'}>{marketStatusText}</Badge>
          </Stack>
        </Box>

        <Divider margin={16} />

        {/* Responsive stock grid: 3 columns on desktop, 1 on mobile */}
        <Box className="stock-ticker-grid">
          {stocks.length > 0 ? (
            stocks.map((stock) => {
              const isPositive = (stock.changePercent ?? 0) >= 0;
              const isFlashing = flashingSymbols.has(stock.symbol || '');
              const changeColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';

              return (
                <Card
                  key={stock.symbol}
                  padding={20}
                  shadow="md"
                  radius="lg"
                  border={true}
                  style={{
                    borderColor: isFlashing
                      ? changeColor
                      : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderWidth: isFlashing ? '2px' : '1px',
                    backgroundColor: isFlashing
                      ? isPositive
                        ? 'var(--ggui-color-success-50, #f0fdf4)'
                        : 'var(--ggui-color-error-50, #fef2f2)'
                      : 'var(--ggui-color-surface, #fafafa)',
                    transition: motionEnabled ? 'all 600ms ease-in-out' : 'none',
                  }}
                  className={isFlashing && motionEnabled ? 'stock-card-flash' : undefined}
                >
                  <Stack gap={12}>
                    {/* Ticker symbol and company name */}
                    <Stack gap={4}>
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {stock.symbol || 'N/A'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name || 'Unknown'}
                      </Text>
                    </Stack>

                    <Divider margin={8} />

                    {/* Price display */}
                    <Stack gap={4}>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Current Price
                      </Text>
                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                    </Stack>

                    {/* Change amount and percentage with color coding */}
                    <Stack direction="horizontal" gap={12} align="center">
                      <Stack direction="horizontal" gap={8} align="center">
                        <Text color={changeColor} weight="semibold">
                          {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                        </Text>
                        <Icon name={isPositive ? 'trend-increasing' : 'trend-decreasing'} size={16} color={changeColor} />
                        <Text color={changeColor} weight="semibold">
                          {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No stocks to display</Text>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // Step state
  const [currentStep, setCurrentStep] = useState(1);

  // Form data state
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Email validation helper
  const validateEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  // Validate step 1 fields
  const validateStep1 = useCallback((): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!formData.email.trim()) newErrors.email = 'Email is required';
    else if (!validateEmail(formData.email)) newErrors.email = 'Invalid email format';
    if (!formData.avatar) newErrors.avatar = 'Avatar selection is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData.name, formData.email, formData.avatar, validateEmail]);

  // Validate step 2 fields
  const validateStep2 = useCallback((): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.role) newErrors.role = 'Role is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData.role]);

  // Handle next button
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
        setErrors({});
      }
    } else if (currentStep === 2) {
      if (validateStep2()) {
        setCurrentStep(3);
        setErrors({});
      }
    }
  }, [currentStep, validateStep1, validateStep2]);

  // Handle back button
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  }, [currentStep]);

  // Handle complete/submit
  const handleComplete = useCallback(() => {
    complete(formData);
  }, [formData, complete]);

  // Handle form field changes
  const handleFieldChange = useCallback((field: string, value: unknown) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  // Determine if Next button should be disabled
  const isNextDisabled = useCallback((): boolean => {
    if (currentStep === 1) {
      return !formData.name.trim() || !formData.email.trim() || !formData.avatar;
    } else if (currentStep === 2) {
      return !formData.role;
    }
    return false;
  }, [currentStep, formData.name, formData.email, formData.avatar, formData.role]);

  return { complete, currentStep, setCurrentStep, formData, handleFieldChange, handleNext, handleBack, handleComplete, errors, validateEmail, isNextDisabled };
}

export default function Component(props: Props) {
  const { complete, currentStep, setCurrentStep, formData, handleFieldChange, handleNext, handleBack, handleComplete, errors, validateEmail, isNextDisabled } = useComponent(props);

  // Compute progress percentage
  const progressPercent = (currentStep / 3) * 100;

  return (
    <Container maxWidth="md" padding={`var(--ggui-spacing-8, 32px)`}>
      <Stack gap={`var(--ggui-spacing-8, 32px)`} align="center">
        {/* Header with step indicator */}
        <Stack gap={`var(--ggui-spacing-4, 16px)`} align="center" direction="vertical" style={{ width: '100%' }}>
          <Heading level={1} align="center">Onboarding Setup</Heading>
          <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 3
          </Text>
          {/* Progress Bar */}
          <Box style={{ width: '100%', background: 'var(--ggui-color-outlineVariant, #e4e4e7)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', height: '4px', overflow: 'hidden' }}>
            <Box style={{ background: 'var(--ggui-color-primary-600, #0284c7)', height: '100%', width: `${progressPercent}%`, transition: 'width 300ms ease-out' }} />
          </Box>
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding={`var(--ggui-spacing-6, 24px)`} shadow="md" style={{ width: '100%' }}>
            <Stack gap={`var(--ggui-spacing-6, 24px)`}>
              <Heading level={2}>Profile Setup</Heading>

              {/* Name Input */}
              <Input
                label="Full Name"
                value={formData.name}
                onChange={(value) => handleFieldChange('name', value)}
                placeholder="John Doe"
                required
                error={errors.name}
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                value={formData.email}
                onChange={(value) => handleFieldChange('email', value)}
                placeholder="john@example.com"
                required
                error={errors.email}
              />

              {/* Avatar Selection */}
              <Stack gap={`var(--ggui-spacing-2, 8px)`} direction="vertical">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar Selection <span style={{ color: 'var(--ggui-color-error-500, #dc2626)' }}>*</span></Text>
                <Stack gap={`var(--ggui-spacing-3, 12px)`} direction="horizontal" wrap>
                  {(props.avatarOptions || []).map((avatar) => (
                    <Box
                      key={avatar}
                      as={Clickable}
                      onClick={() => handleFieldChange('avatar', avatar)}
                      style={{
                        width: '56px',
                        height: '56px',
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                        border: formData.avatar === avatar ? '3px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '28px',
                        cursor: 'pointer',
                        transition: 'all 200ms ease',
                        background: formData.avatar === avatar ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'transparent',
                      }}
                    >
                      {avatar}
                    </Box>
                  ))}
                </Stack>
                {errors.avatar && <Text variant="caption" color="var(--ggui-color-error-500, #dc2626)">{errors.avatar}</Text>}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding={`var(--ggui-spacing-6, 24px)`} shadow="md" style={{ width: '100%' }}>
            <Stack gap={`var(--ggui-spacing-6, 24px)`}>
              <Heading level={2}>Preferences</Heading>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => handleFieldChange('role', value)}
                options={(props.roleOptions || []).map(role => ({ value: role, label: role }))}
                placeholder="Select a role"
                required
                error={errors.role}
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={(value) => handleFieldChange('emailNotifications', value)}
                size="md"
              />

              {/* Theme Preference */}
              <RadioGroup
                label="Theme Preference"
                value={formData.theme}
                onChange={(value) => handleFieldChange('theme', value)}
                options={[
                  { value: 'light', label: 'Light' },
                  { value: 'dark', label: 'Dark' },
                ]}
                direction="horizontal"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding={`var(--ggui-spacing-6, 24px)`} shadow="md" style={{ width: '100%' }}>
            <Stack gap={`var(--ggui-spacing-6, 24px)`}>
              <Heading level={2}>Review & Confirm</Heading>

              {/* Summary Section */}
              <Stack gap={`var(--ggui-spacing-4, 16px)`}>
                {/* Profile Summary */}
                <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={`var(--ggui-spacing-4, 16px)`} borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap={`var(--ggui-spacing-3, 12px)`}>
                    <Heading level={4} color="var(--ggui-color-primary-900, #0c4a6e)">Profile Information</Heading>
                    <Stack gap={`var(--ggui-spacing-2, 8px)`}>
                      <Row gap={`var(--ggui-spacing-2, 8px)`}>
                        <Text variant="label" style={{ minWidth: '100px' }}>Name:</Text>
                        <Text>{formData.name}</Text>
                      </Row>
                      <Row gap={`var(--ggui-spacing-2, 8px)`}>
                        <Text variant="label" style={{ minWidth: '100px' }}>Email:</Text>
                        <Text>{formData.email}</Text>
                      </Row>
                      <Row gap={`var(--ggui-spacing-2, 8px)`}>
                        <Text variant="label" style={{ minWidth: '100px' }}>Avatar:</Text>
                        <Text style={{ fontSize: '20px' }}>{formData.avatar}</Text>
                      </Row>
                    </Stack>
                  </Stack>
                </Box>

                {/* Preferences Summary */}
                <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={`var(--ggui-spacing-4, 16px)`} borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap={`var(--ggui-spacing-3, 12px)`}>
                    <Heading level={4} color="var(--ggui-color-primary-900, #0c4a6e)">Preferences</Heading>
                    <Stack gap={`var(--ggui-spacing-2, 8px)`}>
                      <Row gap={`var(--ggui-spacing-2, 8px)`}>
                        <Text variant="label" style={{ minWidth: '100px' }}>Role:</Text>
                        <Text>{formData.role}</Text>
                      </Row>
                      <Row gap={`var(--ggui-spacing-2, 8px)`}>
                        <Text variant="label" style={{ minWidth: '100px' }}>Notifications:</Text>
                        <Badge variant={formData.emailNotifications ? 'success' : 'default'}>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                      </Row>
                      <Row gap={`var(--ggui-spacing-2, 8px)`}>
                        <Text variant="label" style={{ minWidth: '100px' }}>Theme:</Text>
                        <Text>{formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}</Text>
                      </Row>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap={`var(--ggui-spacing-4, 16px)`} justify="end" style={{ width: '100%' }}>
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack}>
              Go Back
            </Button>
          )}
          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled()}
            >
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
